class Solution:
    def findRepeatedDnaSequences(self, s: str) -> List[str]:
        sequences = {}
        result = []
        for i in range(len(s) - 9):
            seq = s[i:i+10]
            if seq in sequences:
                sequences[seq] += 1
            else:
                sequences[seq] = 1
        for seq, count in sequences.items():
            if count > 1:
                result.append(seq)
        return result
